SELECT COUNT(*) AS total_transactions
FROM sales_transactions
WHERE sku = 'Variety-8oz-6';

SELECT SUM(st.total_amount) AS total_revenue
FROM sales_transactions st
WHERE st.product_name = 'Variety-8oz-6';

SELECT DISTINCT product_name
FROM sales_transactions
WHERE account = 'MedMen' AND use_date = '2023-07-15';
